from abc import ABC, abstractmethod

# PRODUCT
class Transport(ABC):
    @abstractmethod
    def deliver(self):
        pass

# CONCRETE PRODUCTS
class Truck(Transport):
    def deliver(self):
        print("Deliver by land in a box.")

class Ship(Transport):
    def deliver(self):
        print("Deliver by sea in a container.")

# CREATOR
class Logistics(ABC):
    @abstractmethod
    def create_transport(self) -> Transport:
        pass

    def deliver_order(self):
        transport = self.create_transport()
        transport.deliver()
        print("Order completed")

# CONCRETE CREATORS
class RoadLogistics(Logistics):
    def create_transport(self) -> Transport:
        return Truck()

class SeaLogistics(Logistics):
    def create_transport(self) -> Transport:
        return Ship()

# CLIENT
if __name__ == "__main__":
    config = "road"

    if config == "road":
        logistics = RoadLogistics()
    else:
        logistics = SeaLogistics()

    logistics.deliver_order()

interface Button {
    void render();
    void onClick(Runnable f);
}

class WindowsButton implements Button {
    public void render() { System.out.println("Windows button"); }
    public void onClick(Runnable f) { f.run(); }
}

class HTMLButton implements Button {
    public void render() { System.out.println("<button>HTML</button>"); }
    public void onClick(Runnable f) { f.run(); }
}

abstract class Dialog {
    public abstract Button createButton();

    public void render() {
        Button btn = createButton();
        btn.onClick(() -> System.out.println("Closing..."));
        btn.render();
    }
}

class WindowsDialog extends Dialog {
    public Button createButton() { return new WindowsButton(); }
}

class WebDialog extends Dialog {
    public Button createButton() { return new HTMLButton(); }
}

